from haystack.components.generators import HuggingFaceLocalGenerator
import detoxify

class ToxicityAuditor:
    def __init__(self):
        self.detox = detoxify.Detoxify('original')

    def run(self, query: str, generated: str) -> dict:
        scores = self.detox.predict(generated)
        return {
            'toxicity': scores['toxicity'],
            'severe_toxicity': scores['severe_toxicity'],
            'bias_attrs': {k: v for k, v in scores.items() if 'identity' in k}
        }

# Usage
auditor = ToxicityAuditor()
bias_scores = auditor.run(query, generated_text)
if bias_scores['toxicity'] > 0.5:
    print('⚠️ High toxicity detected')

